module dram_cell (
    input wire D,     // Data input
    input wire WL,    // Word line (activate line)
    input wire RW,    // Read/Write control
    output reg BL     // Bit line (output)
);

    reg cell_content; // Internal storage for the 1-bit DRAM cell

    always @(posedge WL) begin
        if (RW) begin
            // Write operation
            cell_content <= D; 
        end else begin
            // Read operation
            BL <= cell_content; 
        end
    end
endmodule
